    {"id": "ex-mod4-9", "type": "quiz", "question": "Qu'est-ce que les Flags (Drapeaux / EFLAGS) concrètement ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Un registre spécial (RFLAGS) où chaque bit représente un état (ex: le bit 6 est le Zero Flag, le bit 11 est l'Overflow Flag)."}, {"id": "b", "text": "Des variables globales en RAM."}, {"id": "c", "text": "Un système d'exploitation."}], "correctId": "a", "explanation": "L'ALU modifie ces bits après chaque calcul, et les instructions de saut (ex: 'je') ne font que vérifier si un bit précis est à 1."}},
